mapper.select:
select w.id, w.title, m.nickname as artist_name, case w.category when 'DIGITAL_ART' then '디지털 아트' when 'MOTION' then '모션그래픽' when '3D_ANIMATION' then '3D 애니메이션' when 'CINEMATIC' then '시네마틱' when 'EXPERIMENTAL' then '실험' when 'LOOP' then '루프' when 'AI_GENERATED' then 'AI 생성' else w.category end as category, case when exists ( select 1 from tbl_auction a where a.work_id = w.id ) then '경매' else '거래' end as sale_type, w.status, w.created_datetime as created_at, w.view_count, w.price, w.thumbnail as thumbnail_url, ( select wf.file_url from tbl_work_file wf where wf.work_id = w.id and wf.file_type = 'VIDEO' limit 1 ) as video_url, ( select count(*) from tbl_report r where r.target_type = 'WORK' and r.target_id = w.id ) as report_count from tbl_work w join tbl_member m on w.member_id = m.id
w.deleted_datetime is null
and ( w.title ilike '%' || #{keyword} || '%' or m.nickname ilike '%' || #{keyword} || '%' )
and w.status = #{status}
order by w.id desc limit #{size} offset #{offset}
